doctor_id = #{doctorId}, schedule_date = #{scheduleDate}, time_slot = #{timeSlot}, max_number = #{maxNumber}, reserved_number = #{reservedNumber}, status = #{status}, create_time = #{createTime}, update_time = #{updateTime},
